var maximumTotalDamage = function(power) {
    const freq = new Map();
    for (const p of power) freq.set(p, (freq.get(p) || 0) + 1);
    const vals = [...freq.keys()].sort((a, b) => a - b);
    const n = vals.length;
    const dp = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const v = vals[i];
        const gain = freq.get(v) * v;
        // binary search for last index where val <= v - 3
        let lo = 0, hi = i;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (vals[mid] <= v - 3) lo = mid + 1;
            else hi = mid;
        }
        dp[i + 1] = Math.max(dp[i], dp[lo] + gain);
    }
    return dp[n];
};
